1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	type Item = { type: string };
11	type QuoteStep = { op: "quote"; items: Item[] };
12	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
13	
14	const basePremiumFor = (item: Item) => BASE_PREMIUM[item.type];
15	
16	const quote = (step: QuoteStep) => {
17	  const basePremiumTotal = step.items.reduce(
18	    (sum, item) => sum + basePremiumFor(item),
19	    0,
20	  );
21	  return { premium: basePremiumTotal + PROCESSING_FEE };
22	};
23	
24	export const run = (input: Scenario): unknown => {
25	  return { results: input.steps.map(quote) };
26	};
