1	import { describe, it, expect } from "vitest";
2	import { run } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Empty / simplest
6	  it("empty item list quote → premium 5 G (only processing fee)", () => {
7	    const result = run({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums for main items (each + processing fee, no other modifiers)
15	  it("quote single sword → 100 G base + 5 fee = 105 G", () => {
16	    const result = run({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 105 }] });
21	  });
22	  it("quote single amulet → 60 G base + 5 fee = 65 G", () => {
23	    const result = run({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 65 }] });
28	  });
29	  it("quote single staff → 80 G base + 5 fee = 85 G", () => {
30	    const result = run({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 85 }] });
35	  });
36	  it("quote single potion → 40 G base + 5 fee = 45 G", () => {
37	    const result = run({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 45 }] });
42	  });
43	
44	  // Component base premiums
45	  it.todo("quote single rune → 25 G base + 5 fee = 30 G");
46	  it.todo("quote single moonstone → 25 G base + 5 fee = 30 G");
47	
48	  // Block of 3 alike components
49	  it.todo("quote 2 runes → 50 G base + 5 fee = 55 G");
50	  it.todo("quote 3 runes → 60 G base (block) + 5 fee = 65 G");
51	  it.todo("quote 4 runes → 100 G base (no block, requires exactly 3) + 5 fee = 105 G");
52	  it.todo("quote 7 runes → 175 G base + 5 fee = 180 G");
53	
54	  // Alike components — different types do not form a block together
55	  it.todo("quote 2 runes + 1 moonstone → 75 G base + 5 fee = 80 G");
56	  it.todo("quote 3 runes + 3 moonstones → 120 G base (two separate blocks) + 5 fee = 125 G");
57	
58	  // Item-specific modifiers: cursed surcharge applies to the cursed item only
59	  it.todo("quote cursed sword on item-only scope → 100 + 50 curse + 5 fee = 155 G");
60	
61	  // High enchantment item-specific
62	  it.todo("quote sword enchantment 5 → 100 + 30 high-enchant + 5 fee = 135 G (threshold)");
63	  it.todo("quote sword enchantment 4 → 100 + 5 fee = 105 G (below threshold)");
64	  it.todo("quote cursed sword enchantment 5 → 100 + 50 + 30 + 5 = 185 G");
65	
66	  // Policy-wide modifiers
67	  it.todo("quote cursed sword + plain amulet → 160 base + 50 curse + 5 fee = 215 G");
68	  it.todo("quote single sword with customer 2 years → 100 - 20 loyalty + 5 fee = 85 G (threshold)");
69	  it.todo("first quote in scenario triggers first insurance surcharge → 100 + 10 + 5 = 115 G");
70	  it.todo("second quote in scenario gets follow-up contract discount → 100 + 10 first ins - 15 follow-up + 5 = 100 G");
71	
72	  // Rounding in MHPCO's favor
73	  it.todo("premium calculation yielding 197.5 G → rounded up to 198 G");
74	
75	  // Integration examples
76	  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G");
77	  it.todo("long-standing customer's second contract: cursed sword ench 7 → 160 G");
78	
79	  // Unknown item type
80	  it.todo("quote with unknown item type throws (CLI exits non-zero)");
81	
82	  // Claims — standard reimbursement
83	  it.todo("claim regular sword damage 500 → payout 400 (full minus 100 deductible)");
84	  it.todo("claim rune damage 200 → payout 100 (full minus 100 deductible)");
85	
86	  // Claims — enchantment >= 8 (50%)
87	  it.todo("claim steel sword ench 9 damage 1000 → payout 400 (50% then deductible)");
88	
89	  // Claims — dragon material full
90	  it.todo("claim dragon sword ench 5 damage 800 → payout 700 (full then deductible)");
91	
92	  // Claims — both clauses, 50% wins
93	  it.todo("claim dragon sword ench 9 damage 1000 → payout 400 (50% wins, then deductible)");
94	  it.todo("claim dragon sword ench 8 damage 1000 → payout 400 (high-ench threshold then deductible)");
95	
96	  // Deductible per damaged item
97	  it.todo("dragon attack damaging sword 500 + amulet 300 → payout 600 (deductible per item)");
98	
99	  // Multiple items same type
100	  it.todo("policy with two swords, two sword damages → both processed separately");
101	  it.todo("claim with more damages of a type than insured → throws");
102	
103	  // Cap exhaustion
104	  it.todo("sword cap 2000; two claims 1500 each → first payout 1400 cap 600, second payout 600 cap 0");
105	  it.todo("cap based on unmodified insurance value (cursed sword cap 2000)");
106	  it.todo("sword + 3 runes insurance sum 1750 (block discount doesn't affect insurance sum)");
107	
108	  // Claims — payout rounding (down in MHPCO's favor)
109	  it.todo("payout calculation yielding 350.5 G → rounded down to 350 G");
110	
111	  // Claims — errors
112	  it.todo("claim for item not in policy throws");
113	  it.todo("claim with negative damage amount throws");
114	});
